// // This module implements a 4-bit universal shift register that performs different operations based on the MODE input. It can hold its current data, perform a left shift with the least significant bit filled by DATAIN, perform a right shift with the most significant bit filled by DATAIN, or load new data from DATAIN directly. The operation is triggered on the falling edge of the clock, and it can be reset to zero when the reset signal is deactivated.
module top_module(DATAOUT, clock, reset, MODE, DATAIN);output reg [3:0] DATAOUT;
  input clock, reset;
  input [1:0] MODE;
  input [3:0] DATAIN;

  always @(posedge clock)
  begin
    if(reset)
      DATAOUT <= 0;
    else
      begin
        case(MODE)
          2'b00 : DATAOUT <= DATAOUT;      
          2'b01 : DATAOUT <= {DATAIN[0], DATAOUT[3:1]};
          2'b10 : DATAOUT <= {DATAOUT[2:0], DATAIN[0]};
          2'b11 : DATAOUT <= DATAIN;       
        endcase
      end
  end

endmodule
